/**
 * Prompt-facing mirror of the curated component registry that lives in
 * `component-registry/` at the repo root. The folder holds the real source +
 * design tokens; this file is the typed catalog injected into the AI system
 * prompt so the agent knows exactly which components it may use and how to
 * install them.
 *
 * Keep this in sync with `component-registry/manifest.json`. The manifest is
 * generated by `component-registry/scripts/fetch-components.mjs`; when you add
 * components there, mirror the new rows here (future: codegen this from the
 * manifest at build time).
 */

export type ComponentRegistryLib = 'shadcn' | 'watermelon';

export interface ComponentRegistryItem {
    /** Registry slug, e.g. "button". */
    name: string;
    lib: ComponentRegistryLib;
    /** Coarse grouping for prompt readability. */
    category: string;
    description: string;
    /** Exported symbol, e.g. "Button". */
    componentName: string;
    /** In-project import path once installed. */
    importPath: string;
    /** URL passed to `bunx --bun shadcn@latest add "<installUrl>"`. */
    installUrl: string;
}

