/**
 * Compact summary of the design-token contract (full source:
 * `component-registry/theme/tokens.css`). These CSS variables ARE the palette —
 * the agent styles with `bg-background`, `text-foreground`, `border-border`,
 * `ring-ring`, etc., and never hardcodes a hex.
 */
export const WEBLAB_DESIGN_TOKENS_SUMMARY = [
    'Color + radius come ONLY from component-registry/theme/tokens.css (shadcn CSS-var contract):',
    '- Surfaces/text: --background, --foreground, --card(/-foreground), --popover(/-foreground), --muted(/-foreground)',
    '- Actions: --primary(/-foreground) = ink (near-black/near-white), --secondary, --accent (faint neutral hover)',
    '- The ONE whisper accent (muted teal) lives on --ring and --brand-accent only — focus/active/one CTA, never on text',
    '- Lines + state: --border, --input, --ring; --destructive(/-foreground) is muted',
    '- Radius: --radius (differentiate per component class; nested radius = inner + padding)',
    'Fonts come ONLY from component-registry/theme/fonts.md (Direction A: Geist; Direction B: Fraunces + Geist).',
].join('\n');

export const COMPONENT_REGISTRY_INSTALL_HINT =
    'Install a catalog component into the user project with its installUrl: bunx --bun shadcn@latest add "<installUrl>". Components land under @/components/ui (shadcn) or @/components/watermelon-ui (watermelon). Only install what the request needs.';
